%%{init: {
  "theme": "base",
  "themeVariables": {
    "primaryColor": "#1e293b",
    "primaryTextColor": "#f8fafc",
    "primaryBorderColor": "#38bdf8",
    "lineColor": "#64748b",
    "fontFamily": "Inter, sans-serif"
  },
  "themeCSS": "
    .er.entityBox { fill: #1e293b !important; stroke: #38bdf8 !important; stroke-width: 1.5px !important; }
    .er.entityLabel { fill: #38bdf8 !important; font-weight: 700 !important; }
    .er.attributeBoxEven { fill: #0b1329 !important; stroke: rgba(255, 255, 255, 0.08) !important; }
    .er.attributeBoxOdd { fill: #111a36 !important; stroke: rgba(255, 255, 255, 0.08) !important; }
    .er.relationshipLabel { fill: #f8fafc !important; }
    .er.relationshipLabelBox { fill: #1e293b !important; stroke: #38bdf8 !important; }
    .er.relationshipLine { stroke: #64748b !important; stroke-width: 1.5px !important; }
    .er text, .er text *, .er tspan, .er .attributeText, .er .labelText, .er [class*=\"labelText\"], .er [class*=\"attributeText\"] { fill: #e2e8f0 !important; color: #e2e8f0 !important; font-family: Inter, sans-serif !important; }
  "
}}%%
erDiagram
    users {
        UUID id "PK"
        VARCHAR_255 email "UNIQUE NOT NULL"
        VARCHAR_255 password_hash "NOT NULL"
        VARCHAR_255 full_name
        BOOLEAN is_active "NOT NULL DEFAULT true"
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    roles {
        UUID id "PK"
        VARCHAR_50 name "UNIQUE NOT NULL"
        TEXT description
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    user_roles {
        UUID id "PK"
        UUID user_id "FK users(id) NOT NULL"
        UUID role_id "FK roles(id) NOT NULL"
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    teams {
        UUID id "PK"
        VARCHAR_100 name "NOT NULL"
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    team_members {
        UUID id "PK"
        UUID team_id "FK teams(id) NOT NULL"
        UUID user_id "FK users(id) NOT NULL"
        VARCHAR_50 role
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    challenges {
        UUID id "PK"
        VARCHAR_200 title "NOT NULL"
        TEXT description
        VARCHAR_20 difficulty
        UUID created_by "FK users(id) NOT NULL"
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    challenge_settings {
        UUID id "PK"
        UUID challenge_id "FK challenges(id) UNIQUE NOT NULL"
        VARCHAR_50 cloud_provider
        VARCHAR_50 instance_type
        INTEGER max_instances
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    challenge_instances {
        UUID id "PK"
        UUID challenge_id "FK challenges(id) NOT NULL"
        UUID team_id "FK teams(id) NOT NULL"
        VARCHAR_20 status "NOT NULL"
        VARCHAR_255 endpoint_url
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    tickets {
        UUID id "PK"
        VARCHAR_200 title "NOT NULL"
        UUID created_by "FK users(id) NOT NULL"
        UUID assigned_to "FK users(id)"
        VARCHAR_20 status "NOT NULL"
        VARCHAR_20 priority
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    ticket_messages {
        UUID id "PK"
        UUID ticket_id "FK tickets(id) NOT NULL"
        UUID sender_id "FK users(id) NOT NULL"
        TEXT message "NOT NULL"
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
        TIMESTAMP updated_at "NOT NULL DEFAULT NOW()"
    }
    audit_logs {
        UUID id "PK"
        VARCHAR_50 entity_type
        UUID entity_id
        VARCHAR_50 action
        UUID performed_by "FK users(id)"
        JSONB details
        TIMESTAMP created_at "NOT NULL DEFAULT NOW()"
    }
